1917   auto *Phi1 = dyn_cast<PHINode>(BO.getOperand(1));
1918   if (!Phi0 || !Phi1 || !Phi0->hasOneUse() || !Phi1->hasOneUse() ||
1919       Phi0->getNumOperands() != Phi1->getNumOperands())
1920     return nullptr;
